CREATE OR REPLACE FUNCTION fpa_count_memno_loan_rep (as_groupno char, adt_balance timestamp(0) ) RETURNS bigint AS $body$
DECLARE

  li_count integer;

BEGIN
  select  count( distinct membership_no)
  into STRICT   li_count
	from sc_rep_mem_share_loan_bal
	where member_status_code = '0'
	and client_id = pka_com_function.fp_login_pc
	and member_group_no = as_groupno
	and balance_date = adt_balance
	and ( (trim(both norm_loantype) IS NOT NULL AND (trim(both norm_loantype))::text <> '') )
  group by member_group_no;

 return li_count;

end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
